INSERT INTO course_units (level_code, title, theme, grammar, items, position) VALUES
('A1','Saudações','Primeiras frases','Use Привет com amigos e Здравствуйте em situações formais.','["Привет","Здравствуйте","Как дела?","Спасибо","Пожалуйста"]'::jsonb,1),
('A1','Apresentação','Nome e origem','Меня зовут é a forma comum de dizer seu nome.','["Меня зовут Анна.","Я из Бразилии.","Очень приятно.","Я учу русский язык."]'::jsonb,2),
('A2','Rotina de estudo','Aprender melhor','Verbos no presente mudam conforme a pessoa.','["Я слушаю и повторяю.","Я пишу по-русски.","Мне нужно повторить.","Я готов к уроку."]'::jsonb,3),
('B1','Opiniões','Gostos e preferências','Мне нравится funciona como para mim agrada.','["Мне нравится русская музыка.","Я люблю русские фильмы.","Русская кухня очень интересная."]'::jsonb,4),
('B2','Cultura','História e folclore','Frases culturais ajudam a aprender contexto.','["Москва — столица России.","Матрешка — традиционная кукла.","Баба-яга живёт в сказках."]'::jsonb,5),
('C1','Leitura avançada','Texto e contexto','No avançado, o foco é contexto e nuances.','["Я хочу узнать больше о России.","Санкт-Петербург известен музеями.","Чай важен в русской культуре."]'::jsonb,6),
('C2','Fluência','Naturalidade','Treine respostas completas e naturais.','["Я немного говорю по-русски.","Говорите медленнее, пожалуйста.","Я хочу сдать экзамен."]'::jsonb,7);
INSERT INTO v12_stable_lessons (code, level_code, russian, portuguese, pronunciation, category, explanation) VALUES ('v12-1', 'A2', "\u0421\u043f\u0430\u0441\u0438\u0431\u043e", "obrigado", "spasibo", "educa\u00e7\u00e3o", "Atividade est\u00e1vel 1: ouvir, traduzir, pronunciar, escrever e responder.") ON CONFLICT (code) DO NOTHING;
